backend.types:

// Timeline test data
export interface TimelineTest {
  id: number;
  test_name: string;
  test_file: string;
  status: string;
  duration_ms: number;
  started_at: string;
  completed_at: string | null;
  is_flaky?: boolean;
  is_critical?: boolean;
  error_message?: string | null;
}

// Timeline execution data
export interface TimelineData {
  execution_id: number;
  total_duration_ms: number;
  tests: TimelineTest[];
  parallel_groups?: TimelineTest[][];
}

backend.database_functions:

// Get timeline data for execution
export async function getTimelineData(
  executionId: number
): Promise<TimelineData | null> {
  const sql = getSql();

  const execution = await getExecutionById(executionId);
  if (!execution) return null;

  const tests = await sql`
    SELECT
      id,
      test_name,
      test_file,
      status,
      duration_ms,
      started_at,
      completed_at,
      is_flaky,
      is_critical,
      error_message
    FROM test_results
    WHERE execution_id = ${executionId}
    ORDER BY started_at ASC
  `;

  const parallelGroups = groupParallelTests(tests as TimelineTest[]);

  return {
    execution_id: executionId,
    total_duration_ms: execution.duration_ms || 0,
    tests: tests as TimelineTest[],
    parallel_groups: parallelGroups,
  };
}

// Helper to group parallel tests
function groupParallelTests(tests: TimelineTest[]): TimelineTest[][] {
  if (tests.length === 0) return [];

  const groups: TimelineTest[][] = [];
  const sorted = [...tests].sort(
    (a, b) => new Date(a.started_at).getTime() - new Date(b.started_at).getTime()
  );

  let currentGroup: TimelineTest[] = [sorted[0]];
  let groupEndTime = new Date(sorted[0].completed_at || sorted[0].started_at).getTime();

  for (let i = 1; i < sorted.length; i++) {
    const test = sorted[i];
    const testStartTime = new Date(test.started_at).getTime();

    if (testStartTime < groupEndTime) {
      currentGroup.push(test);
      const testEndTime = new Date(test.completed_at || test.started_at).getTime();
      groupEndTime = Math.max(groupEndTime, testEndTime);
    } else {
      groups.push(currentGroup);
      currentGroup = [test];
      groupEndTime = new Date(test.completed_at || test.started_at).getTime();
    }
  }

  groups.push(currentGroup);
  return groups;
}

backend.api_route:

import { getTimelineData } from "@/lib/db";
import { NextRequest, NextResponse } from "next/server";

export const dynamic = "force-dynamic";

export async function GET(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await params;
    const executionId = parseInt(id);

    if (isNaN(executionId)) {
      return NextResponse.json(
        { error: "Invalid execution ID" },
        { status: 400 }
      );
    }

    const timeline = await getTimelineData(executionId);

    if (!timeline) {
      return NextResponse.json(
        { error: "Execution not found" },
        { status: 404 }
      );
    }

    return NextResponse.json(timeline);
  } catch (error) {
    console.error("Error fetching timeline:", error);
    return NextResponse.json(
      { error: "Failed to fetch timeline" },
      { status: 500 }
    );
  }
}

frontend.component:

"use client";

import { useEffect, useState } from "react";
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  Tooltip,
  ResponsiveContainer,
  Cell,
  ReferenceLine,
} from "recharts";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Clock, CheckCircle2, XCircle, AlertTriangle } from "lucide-react";

interface TimelineTest {
  id: number;
  test_name: string;
  test_file: string;
  status: string;
  duration_ms: number;
  started_at: string;
  completed_at: string | null;
  is_flaky?: boolean;
  is_critical?: boolean;
  error_message?: string | null;
}

interface TimelineData {
  execution_id: number;
  total_duration_ms: number;
  tests: TimelineTest[];
}

interface TestTimelineProps {
  executionId: number;
}

const STATUS_COLORS = {
  passed: "#22c55e",
  failed: "#ef4444",
  skipped: "#a1a1aa",
  timedout: "#f97316",
};

export function TestTimeline({ executionId }: TestTimelineProps) {
  const [data, setData] = useState<TimelineData | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    async function fetchData() {
      try {
        const response = await fetch(`/api/executions/${executionId}/timeline`);
        const json = await response.json();
        setData(json);
      } catch (error) {
        console.error("Failed to fetch timeline:", error);
      } finally {
        setLoading(false);
      }
    }

    fetchData();
  }, [executionId]);

  if (loading) {
    return (
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Clock className="h-5 w-5" />
            Test Timeline
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="h-[300px] bg-muted animate-pulse rounded" />
        </CardContent>
      </Card>
    );
  }

  if (!data || data.tests.length === 0) {
    return (
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Clock className="h-5 w-5" />
            Test Timeline
          </CardTitle>
        </CardHeader>
        <CardContent>
          <p className="text-muted-foreground">No test data available</p>
        </CardContent>
      </Card>
    );
  }

  const chartData = data.tests.map((test, index) => ({
    index,
    name: test.test_name.length > 30
      ? test.test_name.substring(0, 30) + "..."
      : test.test_name,
    fullName: test.test_name,
    duration: test.duration_ms / 1000,
    status: test.status,
    file: test.test_file,
    isFlaky: test.is_flaky,
    isCritical: test.is_critical,
    errorMessage: test.error_message,
    ...test,
  }));

  const avgDuration =
    data.tests.reduce((sum, t) => sum + t.duration_ms, 0) /
    data.tests.length /
    1000;

  const formatDuration = (seconds: number) => {
    if (seconds < 1) return `${(seconds * 1000).toFixed(0)}ms`;
    if (seconds < 60) return `${seconds.toFixed(1)}s`;
    return `${(seconds / 60).toFixed(1)}m`;
  };

  return (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center justify-between">
          <span className="flex items-center gap-2">
            <Clock className="h-5 w-5" />
            Test Timeline
          </span>
          <div className="flex items-center gap-4 text-sm font-normal">
            <span className="flex items-center gap-1">
              <span className="w-3 h-3 bg-green-500 rounded" />
              Passed
            </span>
            <span className="flex items-center gap-1">
              <span className="w-3 h-3 bg-red-500 rounded" />
              Failed
            </span>
            <span className="flex items-center gap-1">
              <span className="w-3 h-3 bg-zinc-400 rounded" />
              Skipped
            </span>
          </div>
        </CardTitle>
      </CardHeader>
      <CardContent>
        <div className="h-[400px]">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart
              data={chartData}
              layout="vertical"
              margin={{ top: 10, right: 30, left: 150, bottom: 10 }}
            >
              <XAxis
                type="number"
                tickFormatter={formatDuration}
                domain={[0, "auto"]}
                tick={{ fontSize: 12 }}
              />
              <YAxis
                type="category"
                dataKey="name"
                width={140}
                tick={{ fontSize: 11 }}
                interval={0}
              />
              <Tooltip
                content={({ active, payload }) => {
                  if (active && payload && payload.length) {
                    const test = payload[0].payload;
                    return (
                      <div className="bg-popover border rounded-lg p-3 shadow-lg max-w-xs">
                        <p className="font-medium text-sm mb-1">{test.fullName}</p>
                        <p className="text-xs text-muted-foreground mb-2">{test.file}</p>
                        <div className="flex items-center gap-2 mb-1">
                          {test.status === "passed" ? (
                            <CheckCircle2 className="h-4 w-4 text-green-500" />
                          ) : test.status === "failed" ? (
                            <XCircle className="h-4 w-4 text-red-500" />
                          ) : (
                            <AlertTriangle className="h-4 w-4 text-amber-500" />
                          )}
                          <span className="capitalize">{test.status}</span>
                          {test.isFlaky && (
                            <Badge variant="outline" className="text-xs">Flaky</Badge>
                          )}
                          {test.isCritical && (
                            <Badge variant="destructive" className="text-xs">Critical</Badge>
                          )}
                        </div>
                        <p className="text-sm">
                          Duration: <strong>{formatDuration(test.duration)}</strong>
                        </p>
                        {test.errorMessage && (
                          <p className="text-xs text-red-500 mt-2 truncate">
                            {test.errorMessage.substring(0, 100)}...
                          </p>
                        )}
                      </div>
                    );
                  }
                  return null;
                }}
              />
              <ReferenceLine
                x={avgDuration}
                stroke="#888"
                strokeDasharray="3 3"
                label={{
                  value: `Avg: ${formatDuration(avgDuration)}`,
                  position: "top",
                  fontSize: 10,
                }}
              />
              <Bar
                dataKey="duration"
                radius={[0, 4, 4, 0]}
              >
                {chartData.map((entry, index) => (
                  <Cell
                    key={`cell-${index}`}
                    fill={STATUS_COLORS[entry.status as keyof typeof STATUS_COLORS] || "#888"}
                    cursor="pointer"
                  />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>

        <div className="mt-4 grid grid-cols-4 gap-4 text-center border-t pt-4">
          <div>
            <p className="text-sm text-muted-foreground">Total Tests</p>
            <p className="text-xl font-semibold">{data.tests.length}</p>
          </div>
          <div>
            <p className="text-sm text-muted-foreground">Total Duration</p>
            <p className="text-xl font-semibold">
              {formatDuration(data.total_duration_ms / 1000)}
            </p>
          </div>
          <div>
            <p className="text-sm text-muted-foreground">Avg Duration</p>
            <p className="text-xl font-semibold">{formatDuration(avgDuration)}</p>
          </div>
          <div>
            <p className="text-sm text-muted-foreground">Slowest</p>
            <p className="text-xl font-semibold">
              {formatDuration(Math.max(...data.tests.map((t) => t.duration_ms)) / 1000)}
            </p>
          </div>
        </div>
      </CardContent>
    </Card>
  );
}


"use client";

import { useEffect, useState, useMemo } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import {
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
} from "@/components/ui/tooltip";
import { Clock, CheckCircle2, XCircle } from "lucide-react";

interface TimelineTest {
  id: number;
  test_name: string;
  test_file: string;
  status: string;
  duration_ms: number;
  started_at: string;
  completed_at: string | null;
}

interface TimelineData {
  execution_id: number;
  total_duration_ms: number;
  tests: TimelineTest[];
}

interface TestGanttProps {
  executionId: number;
}

const STATUS_COLORS = {
  passed: "bg-green-500",
  failed: "bg-red-500",
  skipped: "bg-zinc-400",
  timedout: "bg-orange-500",
};

export function TestGantt({ executionId }: TestGanttProps) {
  const [data, setData] = useState<TimelineData | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    async function fetchData() {
      try {
        const response = await fetch(`/api/executions/${executionId}/timeline`);
        const json = await response.json();
        setData(json);
      } catch (error) {
        console.error("Failed to fetch timeline:", error);
      } finally {
        setLoading(false);
      }
    }

    fetchData();
  }, [executionId]);

  const { startTime, endTime, totalDuration } = useMemo(() => {
    if (!data?.tests.length) return { startTime: 0, endTime: 0, totalDuration: 0 };

    const times = data.tests.map((t) => new Date(t.started_at).getTime());
    const endTimes = data.tests.map((t) =>
      new Date(t.completed_at || t.started_at).getTime() + t.duration_ms
    );

    const start = Math.min(...times);
    const end = Math.max(...endTimes);

    return {
      startTime: start,
      endTime: end,
      totalDuration: end - start,
    };
  }, [data]);

  if (loading) {
    return (
      <Card>
        <CardContent className="py-6">
          <div className="h-[200px] bg-muted animate-pulse rounded" />
        </CardContent>
      </Card>
    );
  }

  if (!data || data.tests.length === 0) {
    return null;
  }

  const formatDuration = (ms: number) => {
    if (ms < 1000) return `${ms}ms`;
    if (ms < 60000) return `${(ms / 1000).toFixed(1)}s`;
    return `${(ms / 60000).toFixed(1)}m`;
  };

  return (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <Clock className="h-5 w-5" />
          Execution Timeline (Gantt)
        </CardTitle>
      </CardHeader>
      <CardContent>
        <div className="space-y-1">
          <TooltipProvider>
            {data.tests.map((test) => {
              const testStart = new Date(test.started_at).getTime();
              const left = ((testStart - startTime) / totalDuration) * 100;
              const width = (test.duration_ms / totalDuration) * 100;

              return (
                <Tooltip key={test.id}>
                  <TooltipTrigger asChild>
                    <div className="relative h-6 bg-muted/30 rounded">
                      <div
                        className={`absolute h-full rounded ${
                          STATUS_COLORS[test.status as keyof typeof STATUS_COLORS] || "bg-gray-400"
                        } opacity-80 hover:opacity-100 transition-opacity cursor-pointer`}
                        style={{
                          left: `${left}%`,
                          width: `${Math.max(width, 1)}%`,
                        }}
                      />
                      <span className="absolute left-2 top-1/2 -translate-y-1/2 text-xs truncate max-w-[200px]">
                        {test.test_name}
                      </span>
                    </div>
                  </TooltipTrigger>
                  <TooltipContent>
                    <div className="space-y-1">
                      <p className="font-medium">{test.test_name}</p>
                      <p className="text-xs text-muted-foreground">{test.test_file}</p>
                      <div className="flex items-center gap-2">
                        {test.status === "passed" ? (
                          <CheckCircle2 className="h-3 w-3 text-green-500" />
                        ) : (
                          <XCircle className="h-3 w-3 text-red-500" />
                        )}
                        <span className="capitalize text-sm">{test.status}</span>
                        <span className="text-sm">• {formatDuration(test.duration_ms)}</span>
                      </div>
                    </div>
                  </TooltipContent>
                </Tooltip>
              );
            })}
          </TooltipProvider>
        </div>

        <div className="flex justify-between mt-2 text-xs text-muted-foreground">
          <span>0s</span>
          <span>{formatDuration(totalDuration / 2)}</span>
          <span>{formatDuration(totalDuration)}</span>
        </div>
      </CardContent>
    </Card>
  );
}
